     7→} from '../helpers/object-utils';
     8→import { capitalize } from '../helpers/string-utils';
     9→import { Cache } from './cache';
    10→import { Context } from './context';
    11→import { GLOBAL_APP_SESSION_ID } from './helpers';
    12→import { Hooks } from './hooks';
    13→import {
    14→  type CombineSlicesContext,
    15→  type CombineSlicesState,
    16→  type MachineAction,
    17→  type MachineConfig,
    18→  type MachineMetadata,
    19→  type MachineReducer,
    20→  type MachineSelectors,
    21→  type MachineSlices,
    22→  type MachineState,
    23→  type MachineUserID,
    24→  METADATA_FIELD_NAME,
    25→  type SliceContext,
    26→  type StateMachine,
    27→  type StringTypes,
    28→  type UpsertMetadataOperation,
    29→} from './models';
    30→import { Slices } from './slice';
    31→import { Store } from './store';
    32→
    33→export namespace Machine {
    34→  export function GetSelectorsWrapper(params: {
    35→    selectors: MachineSelectors<any> | undefined;
    36→  }) {
    37→    const { selectors } = params;
    38→    const selectorEntries = selectors ? objectEntries(selectors) : null;
    39→    return function injectSelectorValues(state: MachineState) {
    40→      if (!selectorEntries?.length) return state;
    41→      return produce(state, draft => {
    42→        selectorEntries.forEach(([key, fn]) => {
    43→          draft[key] = fn(draft);
    44→        });
    45→      });
    46→    };
    47→  }
    48→
    49→  export function UpsertStateMetadata(params: {
    50→    operation: UpsertMetadataOperation;
    51→    userID: MachineUserID;
    52→    mappedSlices: Slices.SlicesMap;
    53→    currentSessionID: string;
    54→  }) {
    55→    const { operation, userID, mappedSlices, currentSessionID } = params;
    56→
    57→    if (operation.op === 'update') {
    58→      const { originActionType, state, override } = operation;
    59→      const previousMetadata = state[METADATA_FIELD_NAME] as MachineMetadata;
    60→
    61→      assertObject(
    62→        previousMetadata,
    63→        'UpsertStateMetadata failed. No metadata found in state.',
    64→      );
    65→
    66→      const meta = {
    67→        /** NOT updated fields, used for cache invalidation **/
    68→        userID: previousMetadata.userID, // not updated, used by cache strategy
    69→        startedAt: previousMetadata.startedAt, // not updated, used by cache strategy
    70→        slicesCacheStrategy: previousMetadata.slicesCacheStrategy, // not updated, used by cache strategy
    71→        sessionID: previousMetadata.sessionID, // not updated, used by cache strategy
    72→        /** Updated fields **/
    73→        updatedByActionType: originActionType,
    74→        changes: previousMetadata.changes + 1,
    75→        updatedAt: Date.now(),
    76→        ...override,
    77→      } satisfies MachineMetadata;
    78→
    79→      return {
    80→        ...state,
    81→        [METADATA_FIELD_NAME]: meta,
    82→      };
    83→    }
    84→
    85→    // Handling new state
    86→    // prettier-ignore
    87→    const slicesCacheStrategy = {} as MachineMetadata['slicesCacheStrategy'];
    88→
    89→    for (const { slice, sliceKey } of mappedSlices.info) {
    90→      slicesCacheStrategy[sliceKey] = slice.cache;
    91→    }
    92→
    93→    const { state, override } = operation;
    94→    const now = Date.now();
    95→
    96→    const metadata: MachineMetadata = {
    97→      userID,
    98→      updatedAt: now,
    99→      startedAt: now,
   100→      updatedByActionType: '',
   101→      changes: 0,
   102→      slicesCacheStrategy,
   103→      sessionID: currentSessionID,
   104→      ...override,
   105→    };
   106→
   107→    return {
   108→      ...state,
   109→      [METADATA_FIELD_NAME]: metadata,
   110→    };
   111→  }
   112→
   113→  export function RootReducer(params: {
   114→    mappedSlices: Slices.SlicesMap;
   115→    selectors: MachineSelectors<any> | undefined;
   116→    getContext: () => SliceContext;
   117→    getInitialState: () => MachineState;
   118→    machineID: string;
   119→    sessionID: string; // current sessionID
   120→    trackMetadata: boolean;
   121→  }): MachineReducer<any> {
   122→    const {
   123→      machineID,
   124→      getContext,
   125→      getInitialState,
   126→      selectors,
   127→      mappedSlices,
   128→      sessionID,
   129→      trackMetadata,
   130→    } = params;
   131→
   132→    const withSelectorValues = GetSelectorsWrapper({ selectors });
   133→
   134→    return function reducer(rootState = getInitialState(), action) {
   135→      if (action.type === `@@${machineID}/reset`) {
   136→        return action.payload;
   137→      }
   138→
   139→      // prettier-ignore
   140→      const reducer = mappedSlices.reducerByActionType[action.type as StringTypes.ActionType];
   141→
   142→      if (!reducer) {
   143→        return rootState;
   144→      }
   145→
   146→      const sliceKey = reducer.info.sliceKey;
   147→      const previousSliceState = rootState[sliceKey] as MachineState;
   148→      const nextSliceState = reducer(previousSliceState, action);
   149→
   150→      if (previousSliceState === nextSliceState) {
   151→        return rootState;
   152→      }
   153→
   154→      let next = {
   155→        ...rootState,
   156→        [sliceKey]: nextSliceState,
   157→      };
   158→
   159→      if (trackMetadata) {
   160→        next = UpsertStateMetadata({
   161→          currentSessionID: sessionID,
   162→          mappedSlices,
   163→          userID: getContext().userID,
   164→          operation: {
   165→            op: 'update',
   166→            state: next,
   167→            originActionType: action.type,
   168→            override: {},
   169→          },
   170→        });
   171→      }
   172→
   173→      return withSelectorValues(next);
   174→    };
   175→  }
   176→
   177→  /**
   178→   * Factory function to create a new state machine definition.
   179→   * @returns A frozen, read-only state machine definition object.
   180→   * @param config
   181→   */
   182→  export function Create<
   183→    const Slices extends MachineSlices,
   184→    const Selectors extends MachineSelectors<CombineSlicesState<Slices>>,
   185→    const State extends CombineSlicesState<Slices>,
   186→    const Context extends CombineSlicesContext<Slices>,
   187→    const ID extends string,
   188→  >(
   189→    config: MachineConfig<Slices, State, Selectors, Context, ID>,
   190→  ): StateMachine<Slices, State, Selectors, Context, ID> {
   191→    /**
   192→     * Internal values
   193→     */
   194→    const {
   195→      id: ID,
   196→      slices,
   197→      sessionID: currentSessionID = GLOBAL_APP_SESSION_ID,
   198→    } = config;
   199→
   200→    const mappedSlices = Slices.MapSlices(ID, slices);
   201→
   202→    const context = Context.Handler({
   203→      ...mappedSlices.mergedSlicesInitialContext,
   204→      ...config.context,
   205→    });
   206→
   207→    let cacheInvalidationsReport: Cache.StateInvalidationsReport | null = null;
   208→
   209→    let initialState = (() => {
   210→      const { initial, selectors } = config;
   211→      const injectSelectorValues = GetSelectorsWrapper({ selectors });
   212→
   213→      const oldMetadata = initial?.[METADATA_FIELD_NAME];
   214→
   215→      let state = {
   216→        ...mappedSlices.mergedSlicesInitialState,
   217→        ...initial,
   218→      };
   219→
   220→      if (!oldMetadata) {
   221→        state = UpsertStateMetadata({
   222→          userID: config.context?.userID,
   223→          currentSessionID,
   224→          mappedSlices,
   225→          operation: {
   226→            op: 'create',
   227→            state,
   228→            override: {},
   229→          },
   230→        });
   231→        return injectSelectorValues(state);
   232→      }
   233→
   234→      cacheInvalidationsReport = Cache.StateInvalidations({
   235→        mappedSlices,
   236→        currentSessionID,
   237→        getContext: context.get,
   238→        cachedState: initial,
   239→        cachedMetadata: oldMetadata,
   240→      });
   241→
   242→      state = cacheInvalidationsReport.cleanState;
   243→
   244→      state = UpsertStateMetadata({
   245→        userID: config.context?.userID,
   246→        currentSessionID,
   247→        mappedSlices,
   248→        operation: {
   249→          op: 'update',
   250→          originActionType: `@@${ID}/remove_invalid_cache`,
   251→          state,
   252→          override: {},
   253→        },
   254→      });
   255→
   256→      return injectSelectorValues(state);
