    20→
    21→export type MSTimeUnit = (typeof MSUnits)[number];
    22→
    23→/**
    24→ * A string representing time to be converted in milliseconds
    25→ * @example:
    26→ *  - '1s' // => 1000 (1 second)
    27→ *  - '1y' // => 31556952000 (1 year)
    28→ *  - see `ms.spec.ts`
    29→ */
    30→export type MSTimeString = number | `${number}${MSTimeUnit}`;
    31→
    32→export const MS_REGEX = new RegExp(`^(\\d+)(${MSUnits.join('|')})$`);
    33→
    34→/**
    35→ * Converts MSTimeString to milliseconds
    36→ * @example: ms(1s) // => 1000
    37→ * @param timeString
    38→ */
    39→export function ms(timeString: MSTimeString): number {
    40→  if (typeof timeString === 'number') {
    41→    timeString = `${timeString}ms`;
