type UnaryFunction<T, R> = (arg: T) => R;

type ComposableFn = (...args: never[]) => unknown;

/**
 * Composes single-argument functions from right to left. The rightmost
 * function can take multiple arguments; the remaining functions must be unary.
 *
 * @example
 * const add = (n: number) => n + 1;
 * const multiply = (n: number) => n * 2;
 * const toString = (n: number) => `Result: ${n}`;
 *
 * const compute = compose(toString, multiply, add);
 * compute(5); // "Result: 12"
 *
 * @param fns The functions to compose.
 * @returns A new function obtained by composing the input functions
 * from right to left.
 */
export function compose(): <R>(a: R) => R;

export function compose<F extends ComposableFn>(f: F): F;
export function compose<A, B, C>(
  f: UnaryFunction<B, C>,
  g: UnaryFunction<A, B>,
): UnaryFunction<A, C>;
export function compose<A, B, C, D>(
  f: UnaryFunction<C, D>,
  g: UnaryFunction<B, C>,
  h: UnaryFunction<A, B>,
): UnaryFunction<A, D>;
export function compose<A, B, C, D, E>(
  f: UnaryFunction<D, E>,
  g: UnaryFunction<C, D>,
  h: UnaryFunction<B, C>,
  i: UnaryFunction<A, B>,
): UnaryFunction<A, E>;
export function compose<A, B, C, D, E, F>(
  f: UnaryFunction<E, F>,
  g: UnaryFunction<D, E>,
  h: UnaryFunction<C, D>,
  i: UnaryFunction<B, C>,
  j: UnaryFunction<A, B>,
): UnaryFunction<A, F>;

export function compose(
  ...fns: readonly ((...args: unknown[]) => unknown)[]
): unknown {
  if (fns.length === 0) {
    return <T>(arg: T): T => arg;
  }

  if (fns.length === 1) {
    return fns[0];
  }

  return fns.reduce(
    (a, b) =>
      (...args: unknown[]) =>
        a(b(...args)),
  );
}

